import base64, os, subprocess
os.chdir(r"C:\\sistema-catalogos")

# Instala o novo dashboard_web.py
with open("dashboard_web.py", "wb") as f:
    f.write(base64.b64decode(""))
print("✅ dashboard_web.py v4 instalado!")

# Push
cmds = [
    ["git", "add", "dashboard_web.py"],
    ["git", "commit", "-m", "feat: dashboard v4 - config page + todos botoes funcionando"],
    ["git", "push"]
]
for cmd in cmds:
    r = subprocess.run(cmd, capture_output=True, text=True)
    print(' '.join(cmd[:2]), '->', r.stdout.strip() or r.stderr.strip())
print("\n✅ PRONTO! Deploy automático em ~2 minutos.")
print("   Dashboard: https://qubo-dashboard.onrender.com")
print("   Config:    https://qubo-dashboard.onrender.com/config")
